export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface Customer {
  yearsWithMHPCO: number;
}

export interface QuoteStep {
  op: "quote";
  items: Item[];
}

export interface DamageEntry {
  itemType: string;
  amount: number;
}

export interface ClaimStep {
  op: "claim";
  policy: number;
  incident: {
    cause: string;
    damages: DamageEntry[];
  };
}

export type Step = QuoteStep | ClaimStep;

export interface Scenario {
  customer: Customer;
  steps: Step[];
}

export interface QuoteResult {
  premium: number;
}

export interface ClaimResult {
  payout: number;
  remainingCap: number;
}

export type StepResult = QuoteResult | ClaimResult;

export interface ScenarioResult {
  results: StepResult[];
}

import { describe, it, expect } from "vitest";
import { type Scenario, type StepResult } from "./claim-office.js";
import { processScenario } from "./claim-office.js";

describe("Claim Office", () => {
  it.todo("should return premium 5 G for empty item list -- only processing fee");

  describe("Basic item premiums", () => {
    it.todo("should return premium 105 G for a single plain sword (100 base + 5 fee)");
    it.todo("should return premium 65 G for a single plain amulet (60 base + 5 fee)");
    it.todo("should return premium 85 G for a single plain staff (80 base + 5 fee)");
    it.todo("should return premium 45 G for a single plain potion (40 base + 5 fee)");
    it.todo("should return premium 30 G for a single rune (25 base + 5 fee)");
    it.todo("should return premium 30 G for a single moonstone (25 base + 5 fee)");
  });

  describe("Component building block pricing", () => {
    it.todo("should return base premium 50 G for 2 runes (no block) -- 50 + 5 = 55 G");
    it.todo("should return base premium 60 G for 3 runes (block applies) -- 60 + 5 = 65 G");
    it.todo("should return base premium 100 G for 4 runes (no block) -- 100 + 5 = 105 G");
    it.todo("should return base premium 175 G for 7 runes -- 175 + 5 = 180 G");
    it.todo("should return base premium 75 G for 2 runes + 1 moonstone (different types, no block) -- 75 + 5 = 80 G");
    it.todo("should return base premium 120 G for 3 runes + 3 moonstones (two blocks) -- 120 + 5 = 125 G");
  });

  describe("Premium modifiers", () => {
    it.todo("should add 50 % risk surcharge for cursed items (applied to the cursed item's base premium)");
    it.todo("should add 30 % risk surcharge for highly enchanted items (enchantment >= 5)");
    it.todo("should NOT add high-enchantment surcharge for enchantment level 4");
    it.todo("should apply both curse and high-enchantment surcharges when both conditions met");
    it.todo("should apply 20 % loyalty discount for customers with >= 2 years with MHPCO");
    it.todo("should apply 10 % initial assessment surcharge for first insurance");
    it.todo("should apply 15 % discount on each contract after the first (follow-up contract)");
    it.todo("should add 5 G processing fee to every premium");
  });

  describe("Multi-item modifier scope", () => {
    it.todo("should apply item-specific modifiers to the affected item only (cursed sword + plain amulet) -- 210 G before fee");
  });

  describe("Modifier thresholds", () => {
    it.todo("should apply loyalty discount for customer with exactly 2 years with MHPCO");
    it.todo("should apply high-enchantment surcharge for sword with exactly enchantment 5");
    it.todo("should apply both curse and high-enchantment surcharges for cursed sword with exactly enchantment 5");
  });

  describe("Rounding in MHPCO's favor", () => {
    it.todo("should round premium up (e.g. 197.5 -> 198 G)");
    it.todo("should round payout down (e.g. 350.5 -> 350 G)");
  });

  describe("Claim processing - standard reimbursement", () => {
    it.todo("should reimburse damage minus 100 G deductible for regular items (no special clauses)");
    it.todo("should reimburse damage minus 100 G deductible for components like runes");
  });

  describe("Claim processing - special clauses", () => {
    it.todo("should reimburse at 50% of damage for items with enchantment >= 8, then subtract deductible");
    it.todo("should fully reimburse damage for items made of dragon material, then subtract deductible");
    it.todo("should apply 50% rule (not full reimbursement) when both enchantment >= 8 and dragon material apply");
    it.todo("should apply full reimbursement (not 50% rule) for dragon material with enchantment < 8");
    it.todo("should apply 50% rule for steel sword with enchantment >= 8");
  });

  describe("Deductible per damage event", () => {
    it.todo("should apply 100 G deductible once per damaged item");
  });

  describe("Cap and multiple claims", () => {
    it.todo("should cap payout at 2x the insurance sum (sword: cap 2000 G)");
    it.todo("should track remaining cap across successive claims");
    it.todo("should reduce desired payout to remaining cap when cap is insufficient");
  });

  describe("Multiple items of same type", () => {
    it.todo("should sum insurance values and cap for multiple items of same type");
    it.todo("should treat each damage entry as a separate damage with its own deductible");
    it.todo("should reject claim when damages contain more entries of a type than the policy covers");
  });

  describe("Cap exhaustion", () => {
    it.todo("should compute insurance sum as sum of items' insurance values");
    it.todo("should base cap on unmodified insurance values (premium modifiers do not raise the cap)");
    it.todo("should compute insurance sum correctly with component blocks (block discount affects premium only)");
  });

  describe("Integration examples", () => {
    it.todo("should compute premium 165 G for newcomer with cursed sword (0 years, no previous contract)");
    it.todo("should compute premium 160 G for long-standing customer's second contract with cursed high-enchantment sword");
  });

  describe("Error handling", () => {
    it.todo("should exit with non-zero status and write error for unknown item type in quote");
    it.todo("should exit with non-zero status and write error for claim referencing uninsured item");
    it.todo("should exit with non-zero status and write error for claim with negative damage amount");
  });

  describe("Multi-step scenario processing", () => {
    it.todo("should process a quote followed by a claim referencing the policy by step index");
  });
});

