const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

function computeItemBasePremium(item: Item): number {
  return BASE_PREMIUMS[item.type] ?? 0;
}

function computeQuotePremium(items: Item[], _customer: Customer): number {
  const totalBase = items.reduce((sum, item) => sum + computeItemBasePremium(item), 0);
  return totalBase + 5;
}

export function processScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      results.push({ premium: computeQuotePremium(step.items, scenario.customer) });
    }
  }
  return { results };
}

