    } else {
      totalBase += computeItemPremium(item);
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === 3) {
      totalBase += BLOCK_PREMIUM;
    } else {
      totalBase += count * BASE_PREMIUMS[type];
    }
  }
  return totalBase + 5;
}

