export function processScenario(scenario: Scenario): ScenarioResult {
  const results: StepResult[] = [];
  for (const step of scenario.steps) {
    if (step.op === "quote") {
      results.push({ premium: computeQuotePremium(step.items, scenario.customer) });
    }
  }
  return { results };
}

function computeItemPremium(item: Item): number {
  const base = computeItemBasePremium(item);
  let total = base;
  if (item.cursed) {
    total += base * 0.5;
  }
  if (item.enchantment !== undefined && item.enchantment >= 5) {
    total += base * 0.3;
  }
  return total;
}

function computeItemBasePremium(item: Item): number {
  return BASE_PREMIUMS[item.type] ?? 0;
}

function computePolicyBasePremium(items: Item[]): number {
  const componentCounts: Record<string, number> = {};
  let total = 0;
  for (const item of items) {
    if (COMPONENT_TYPES.includes(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += computeItemBasePremium(item);
    }
  }
  for (const [type, count] of Object.entries(componentCounts)) {
    if (count === 3) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * BASE_PREMIUMS[type];
    }
  }
  return total;
}

function computeItemSurcharges(items: Item[]): number {
  let total = 0;
  for (const item of items) {
    if (!COMPONENT_TYPES.includes(item.type)) {
      const base = computeItemBasePremium(item);
      if (item.cursed) {
        total += base * 0.5;
      }
      if (item.enchantment !== undefined && item.enchantment >= 5) {
        total += base * 0.3;
      }
    }
  }
  return total;
}

function computePolicyWideModifiers(policyBase: number, customer: Customer): number {
  let total = 0;
  if (customer.yearsWithMHPCO >= 2) {
    total -= policyBase * 0.2;
  }
  return total;
}

function computeQuotePremium(items: Item[], customer: Customer): number {
  const policyBase = computePolicyBasePremium(items);
  const itemSurcharges = computeItemSurcharges(items);
  const policyModifiers = computePolicyWideModifiers(policyBase, customer);
  return policyBase + itemSurcharges + policyModifiers + 5;
}

